theme.stylesheet:
/* ── Window frame ────────────────────────────────────────────────────────── */
/* xfwm4 rounds only the top corners; the bottom edge stays square. */
[data-theme="xfce"] [data-part="window"] {
  border-radius: var(--window-radius) var(--window-radius) 0 0;
}

/* ── Titlebar ────────────────────────────────────────────────────────────── */
[data-theme="xfce"] [data-part="titlebar"] {
  background: var(--titlebar-bg);
  color: var(--titlebar-fg);
  border-bottom: 1px solid var(--x-xfce-header-border);
  padding: 0 4px;
}

[data-theme="xfce"] [data-part="window"][data-focused="false"] [data-part="titlebar"] {
  background: var(--titlebar-bg-inactive);
  color: var(--titlebar-fg-inactive);
}

[data-theme="xfce"] [data-part="title"] {
  font-size: 12px;
  font-weight: bold;
  text-shadow: var(--x-xfce-title-shadow);
}

[data-theme="xfce"] [data-part="window"][data-focused="false"] [data-part="title"] {
  text-shadow: none;
}

[data-theme="xfce"] [data-part="title-icon"] {
  margin-left: 6px;
  color: var(--titlebar-fg);
}

/* Flat squarish xfwm4 buttons: backdrop appears only on hover. */
[data-theme="xfce"] [data-part="controls"] {
  gap: 2px;
  padding: 0 2px;
}

[data-theme="xfce"] [data-part="control"] {
  width: 25px;
  height: 20px;
  border-radius: 3px;
  background: transparent;
  color: inherit; /* glyph follows the titlebar fg, so it dims when unfocused */
}

[data-theme="xfce"] [data-part="control"]:hover {
  background: var(--x-xfce-control-hover);
}

[data-theme="xfce"] [data-part="control"]:active {
  background: var(--x-xfce-control-active);
}

[data-theme="xfce"] [data-part="control"][data-action="close"]:hover,
[data-theme="xfce"] [data-part="control"][data-action="close"]:active {
  background: var(--x-xfce-close-hover);
  color: var(--titlebar-fg);
}

/* ── GTK button faces (shared by toolbar, generic and segmented controls) ── */
[data-theme="xfce"] [data-part="button"],
[data-theme="xfce"] [data-part="icon-button"],
[data-theme="xfce"] [data-part="segment"] {
  height: 24px;
  padding: 0 10px;
  background: var(--control-bg);
  border: 1px solid var(--control-border);
  border-radius: var(--control-radius);
  box-shadow: var(--control-shadow);
  color: var(--control-fg);
}

[data-theme="xfce"] [data-part="icon-button"] {
  width: 26px;
  padding: 0;
}

[data-theme="xfce"] [data-part="button"]:hover,
[data-theme="xfce"] [data-part="icon-button"]:hover,
[data-theme="xfce"] [data-part="segment"]:hover {
  background: var(--control-bg-hover);
}

[data-theme="xfce"] [data-part="button"]:active,
[data-theme="xfce"] [data-part="button"][data-state="open"],
[data-theme="xfce"] [data-part="icon-button"]:active,
[data-theme="xfce"] [data-part="segment"]:active,
[data-theme="xfce"] [data-part="segment"][data-state="selected"] {
  background: var(--control-bg-active);
  box-shadow: var(--x-xfce-pressed-shadow);
}

/* GTK2 linked segments share their inner borders. */
[data-theme="xfce"] [data-part="segment"] {
  border-radius: 0;
  margin-left: -1px;
}
[data-theme="xfce"] [data-part="segment"]:first-child {
  border-radius: var(--control-radius) 0 0 var(--control-radius);
  margin-left: 0;
}
[data-theme="xfce"] [data-part="segment"]:last-child {
  border-radius: 0 var(--control-radius) var(--control-radius) 0;
}

/* ── Toolbar ─────────────────────────────────────────────────────────────── */
[data-theme="xfce"] [data-part="toolbar"] {
  background: var(--toolbar-bg);
  border-bottom: 1px solid var(--toolbar-border);
}

/* GTK2 toolbar buttons sit flat until hovered, then grow a button face. */
[data-theme="xfce"] [data-part="toolbar-button"] {
  height: 26px;
  min-width: 28px;
  padding: 0 8px;
  background: transparent;
  border: 1px solid transparent;
  border-radius: var(--control-radius);
  color: var(--control-fg);
}

[data-theme="xfce"] [data-part="toolbar-button"]:hover {
  background: var(--control-bg);
  border-color: var(--control-border);
  box-shadow: var(--control-shadow);
}

[data-theme="xfce"] [data-part="toolbar-button"]:active,
[data-theme="xfce"] [data-part="toolbar-button"][data-state="active"] {
  background: var(--control-bg-active);
  border-color: var(--control-border);
  box-shadow: var(--x-xfce-pressed-shadow);
}

[data-theme="xfce"] [data-part="toolbar-button"][aria-disabled="true"],
[data-theme="xfce"] [data-part="toolbar-button"]:disabled {
  color: var(--fg-disabled);
}

/* ── Breadcrumbs: the GTK pathbar, a row of linked toggle buttons ────────── */
[data-theme="xfce"] [data-part="breadcrumb"] {
  height: 24px;
  padding: 0 9px;
  background: var(--control-bg);
  border: 1px solid var(--control-border);
  border-radius: var(--control-radius);
  box-shadow: var(--control-shadow);
  color: var(--control-fg);
}

[data-theme="xfce"] [data-part="breadcrumb"]:hover {
  background: var(--control-bg-hover);
}

/* The crumb you are in reads as a depressed toggle, like Thunar's pathbar. */
[data-theme="xfce"] [data-part="breadcrumb"][data-state="current"] {
  background: var(--control-bg-active);
  box-shadow: var(--x-xfce-pressed-shadow);
  font-weight: bold;
}

[data-theme="xfce"] [data-part="breadcrumbs"] svg {
  color: var(--fg-muted);
}

/* ── Search field: a GTK entry ───────────────────────────────────────────── */
[data-theme="xfce"] [data-part="search-field"] {
  height: 24px;
  min-width: 150px;
  padding: 0 6px;
  background: var(--input-bg);
  border: 1px solid var(--input-border);
  border-radius: var(--input-radius);
  box-shadow: var(--x-xfce-entry-shadow);
  color: var(--input-fg);
}

[data-theme="xfce"] [data-part="search-field"] svg {
  color: var(--fg-muted);
}

[data-theme="xfce"] [data-part="search-field"] input::placeholder {
  color: var(--fg-muted);
}

/* ── Sidebar: the GTK side pane ──────────────────────────────────────────── */
[data-theme="xfce"] [data-part="sidebar"] {
  background: var(--sidebar-bg);
  border-right: 1px solid var(--border);
  padding: 4px 0;
  font-size: 12px;
}

[data-theme="xfce"] [data-part="sidebar-heading"] {
  padding: 6px 10px 2px;
  font-size: 11px;
  font-weight: bold;
  color: var(--fg-muted);
}

[data-theme="xfce"] [data-part="sidebar-item"] {
  width: calc(100% - 8px);
  margin: 1px 4px;
  padding: 0 6px;
  border-radius: 2px;
  color: var(--sidebar-fg);
}

[data-theme="xfce"] [data-part="sidebar-item"]:hover {
  background: var(--x-xfce-hover);
}

[data-theme="xfce"] [data-part="sidebar-item"][data-state="selected"] {
  background: var(--sidebar-selected-bg);
  color: var(--sidebar-selected-fg);
}

[data-theme="xfce"] [data-part="sidebar-item-icon"] {
  color: var(--fg-muted);
}

[data-theme="xfce"] [data-part="sidebar-item"][data-state="selected"] [data-part="sidebar-item-icon"] {
  color: var(--sidebar-selected-fg);
}

/* Inline eject on removable-volume rows — the tab-close treatment. */
[data-theme="xfce"] [data-part="sidebar-item-action"] {
  width: 15px;
  height: 15px;
  border: 1px solid transparent;
  border-radius: 3px;
  color: var(--fg-muted);
}

[data-theme="xfce"] [data-part="sidebar-item-action"]:hover {
  border-color: var(--border);
  background: var(--control-bg-hover);
  color: var(--fg);
}

[data-theme="xfce"] [data-part="sidebar-item"][data-state="selected"] [data-part="sidebar-item-action"] {
  color: var(--sidebar-selected-fg);
}

/* Sidebar border carries the visual split; the divider stays a hit area
   with a hairline painted down its center. */
[data-theme="xfce"] [data-part="split-divider"] {
  background: linear-gradient(
    to right,
    transparent 2px,
    var(--border) 2px,
    var(--border) 3px,
    transparent 3px
  );
}

/* ── File list: a GTK2 treeview ──────────────────────────────────────────── */
[data-theme="xfce"] [data-part="file-list"] {
  background: var(--list-bg);
  font-size: 12px;
}

/* Column headers are button-like gradient cells with shared 1px borders. */
[data-theme="xfce"] [data-part="file-list-header"] {
  background: var(--list-header-bg);
  border-bottom: 1px solid var(--border);
}

[data-theme="xfce"] [data-part="file-list-col"] {
  height: 100%;
  display: flex;
  align-items: center;
  border-right: 1px solid var(--border);
  box-shadow: inset 0 1px 0 var(--bevel-lighter);
  color: var(--list-header-fg);
}

[data-theme="xfce"] [data-part="file-list-col"][data-state="sorted"] {
  background: var(--control-bg-active);
  box-shadow: var(--x-xfce-pressed-shadow);
}

/* GTK2 treeviews have no hover state — selection only. */
[data-theme="xfce"] [data-part="file-row"][data-state="selected"] {
  background: var(--selection-bg);
  color: var(--selection-fg);
}

/* GTK convention: selection grays out while the treeview loses focus. */
[data-theme="xfce"] [data-part="file-list"]:not(:focus-within) [data-part="file-row"][data-state="selected"] {
  background: var(--x-xfce-selection-inactive);
  color: var(--fg);
}

[data-theme="xfce"] [data-part="file-row"][data-zebra="even"]:not([data-state="selected"]) {
  background: var(--list-zebra);
}

[data-theme="xfce"] [data-part="file-icon"] {
  color: var(--fg-muted);
}

[data-theme="xfce"] [data-part="file-row"][data-state="selected"] [data-part="file-icon"] {
  color: var(--selection-fg);
}

[data-theme="xfce"] [data-part="file-cell"]:not([data-col="name"]) {
  color: var(--fg-muted);
}

[data-theme="xfce"] [data-part="file-row"][data-state="selected"] [data-part="file-cell"] {
  color: inherit;
}

/* ── Icon grid: GTK2 icon view — the whole cell takes the selection fill ── */
[data-theme="xfce"] [data-part="icon-grid"] {
  background: var(--list-bg);
}
[data-theme="xfce"] [data-part="icon-grid-item"] {
  border: 1px solid transparent;
  border-radius: 3px;
}
[data-theme="xfce"] [data-part="icon-grid-item"][data-state="selected"] {
  background: var(--selection-bg);
  border-color: var(--border-strong);
  color: var(--selection-fg);
}
[data-theme="xfce"] [data-part="icon-grid"]:not(:focus-within) [data-part="icon-grid-item"][data-state="selected"] {
  background: var(--x-xfce-selection-inactive);
  color: var(--fg);
}

[data-theme="xfce"] [data-part="list-empty"] {
  color: var(--fg-muted);
}

/* ── Scrollbars: bordered GTK2 trough + rounded gradient slider ──────────── */
[data-theme="xfce"] ::-webkit-scrollbar-track {
  background: var(--scrollbar-track);
  border: 1px solid var(--border);
}

[data-theme="xfce"] ::-webkit-scrollbar-thumb {
  background: var(--x-xfce-scroll-thumb);
  border: 1px solid var(--border-strong);
  border-radius: 2px;
}

[data-theme="xfce"] ::-webkit-scrollbar-thumb:hover {
  background: var(--x-xfce-scroll-thumb-hover);
}

[data-theme="xfce"] ::-webkit-scrollbar-corner {
  background: var(--scrollbar-track);
}

/* ── Terminal: xfce4-terminal's Tango defaults ───────────────────────────── */
[data-theme="xfce"] [data-part="terminal-panel"] {
  /* Chrome surface, not terminal black: the resize grip + header are window
     chrome; only the host paints the terminal background. */
  background: var(--surface);
  border-top: 1px solid var(--border-strong);
}

/* The header reads as a light GTK notebook strip above the dark terminal. */
[data-theme="xfce"] [data-part="terminal-header"] {
  height: 25px;
  padding: 0 8px;
  background: var(--toolbar-bg);
  border-bottom: 1px solid var(--border);
  color: var(--fg-muted);
  font-size: 11px;
  font-weight: bold;
}

[data-theme="xfce"] [data-part="terminal-host"] {
  background: var(--terminal-bg);
  color: var(--terminal-fg);
  padding: 4px 6px;
  font-family: var(--font-mono);
}

/* ── Status bar ──────────────────────────────────────────────────────────── */
[data-theme="xfce"] [data-part="status-bar"] {
  height: 24px;
  background: var(--x-xfce-statusbar-bg);
  border-top: 1px solid var(--border);
  color: var(--fg-muted);
  font-size: 11px;
}

/* ── Menus ───────────────────────────────────────────────────────────────── */
[data-theme="xfce"] [data-part="menu"] {
  background: var(--x-xfce-menu-bg);
  border: 1px solid var(--border-strong);
  box-shadow: var(--x-xfce-menu-shadow);
  padding: 2px;
  font-size: 12px;
}

[data-theme="xfce"] [data-part="menu-item"] {
  padding: 3px 18px 3px 8px;
  color: var(--fg);
}

[data-theme="xfce"] [data-part="menu-item"]:hover,
[data-theme="xfce"] [data-part="menu-item"]:focus-visible {
  background: var(--selection-bg);
  color: var(--selection-fg);
  outline: none;
}

[data-theme="xfce"] [data-part="menu-item"][aria-disabled="true"] {
  color: var(--fg-disabled);
}

[data-theme="xfce"] [data-part="menu-item"][aria-disabled="true"]:hover {
  background: transparent;
  color: var(--fg-disabled);
}

[data-theme="xfce"] [data-part="menu-separator"] {
  height: 1px;
  margin: 3px 1px;
  background: var(--border);
}

/* ── In-page tabs (⌘T) — a GTK2 notebook: sunken strip, raised active page ─ */
[data-theme="xfce"] [data-part="tab-bar"] {
  background: var(--surface-sunken);
  border-bottom: 1px solid var(--border-strong);
  padding: 3px 4px 0;
  gap: 1px;
}

[data-theme="xfce"] [data-part="tab"] {
  height: 24px;
  min-height: 24px;
  color: var(--fg-muted);
  border: 1px solid var(--border);
  border-bottom: none;
  border-radius: 3px 3px 0 0;
  background: var(--surface-raised);
}

[data-theme="xfce"] [data-part="tab"][data-state="selected"] {
  color: var(--fg);
  border-color: var(--border-strong);
  background: var(--surface);
  /* GTK2 marks the current notebook page with the selection-blue lip. */
  box-shadow: inset 0 2px 0 var(--accent);
}

[data-theme="xfce"] [data-part="tab-close"],
[data-theme="xfce"] [data-part="tab-add"] {
  width: 15px;
  height: 15px;
  border: 1px solid transparent;
  border-radius: 3px;
  font-size: 12px;
  line-height: 1;
  color: var(--fg-muted);
}

[data-theme="xfce"] [data-part="tab-close"]:hover,
[data-theme="xfce"] [data-part="tab-add"]:hover {
  border-color: var(--border);
  background: var(--control-bg-hover);
  color: var(--fg);
}

[data-theme="xfce"] [data-part="tab-add"] {
  align-self: center;
  margin: 0 3px 3px;
}

/* ── Modal dialogs: a flat GTK2 message dialog ───────────────────────────── */
[data-theme="xfce"] [data-part="dialog-overlay"] {
  background: rgba(0, 0, 0, 0.2);
}

[data-theme="xfce"] [data-part="dialog"] {
  background: var(--surface);
  border: 1px solid #5c5c5c;
  border-radius: 2px;
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.45);
}

[data-theme="xfce"] [data-part="dialog-title"] {
  font-weight: 700;
}

[data-theme="xfce"] [data-part="text-input"] {
  background: #ffffff;
  border: 1px solid #888888;
  border-radius: 2px;
  padding: 4px 6px;
}
